def word_freq(text: str) -> dict[str, int]:
    """
    Returns a dictionary mapping each distinct word in text (lowercased) to its count.
    A word is a maximal run of ASCII letters and digits.
    Any other character (punctuation, whitespace, unicode, etc.) is a separator.
    """
    if not text:
        return {}

    result = {}
    current_word = []

    for char in text:
