            current_word.append(char)
        else:
            if current_word:
                word = ''.join(current_word).lower()
                result[word] = result.get(word, 0) + 1
                current_word = []

    # Don't forget the last word if the text doesn't end with a separator
    if current_word:
        word = ''.join(current_word).lower()
        result[word] = result.get(word, 0) + 1

    return result
