def word_freq(text: str) -> dict[str, int]:
    import re
    words = re.findall(r'[a-zA-Z0-9]+', text)
    counts = {}
    for w in words:
        w = w.lower()
        counts[w] = counts.get(w, 0) + 1
    return counts

